/* CSS Exits Classes mapping to Animate.css */
.animate__fadeOutDown {
  animation-name: fadeOutDown;
}
.animate__slideOutLeft {
  animation-name: slideOutLeft;
}

js:
// JS Exits Trigger Logic
function triggerExit(aniName) {
  const el = document.getElementById('preview-box');
  el.className = 'preview-object';
  void el.offsetWidth; // Reflow
  el.classList.add('animate__animated', `animate__${aniName}`);
}
